-#!/usr/bin/env node
-// End-to-end wall-clock benchmark for WasmBackend vs TransformersJsBackend.
-// Runs both on a handful of input lengths; reports warm forward time.
-//
-//     bun scripts/bench-e2e.mjs --scratch-dir /tmp/pii-wasm-e2e
-//
-// Requires the full blob produced by `gen-full-parity-fixture.py`.
-
-import { parseArgs } from "node:util";
-import { join } from "node:path";
-import { WasmBackend } from "../src/js/backends/wasm.ts";
-import { TransformersJsBackend } from "../src/js/backends/transformers-js.ts";
-import { ModelLoader } from "../src/js/model/loader.ts";
-import { Tokenizer } from "../src/js/model/tokenizer.ts";
-
-const SEEDS = [
-  "Hi, my name is John Smith.",  // ~10 tokens
-  "Please email me at jane.doe@example.com about invoice 4511 or call (555) 123-4567.",
-  "My SSN is 123-45-6789 and my bank account is 9876543210. I live at 456 Oak Avenue, " +
-    "Boston, MA 02134. Call me at (617) 555-0199 or text my cell at 617.555.0123.",
-];
-
-const WARMUP = 2;
-const ITERS = 5;
-
-function fmtMs(ns) { return (ns / 1e6).toFixed(1); }
-
-async function measureBackend(backend, tokenIds, mask, label) {
-  for (let i = 0; i < WARMUP; i++) await backend.forward(tokenIds, mask);
-  const samples = [];
-  for (let i = 0; i < ITERS; i++) {
-    const t0 = process.hrtime.bigint();
-    await backend.forward(tokenIds, mask);
-    samples.push(Number(process.hrtime.bigint() - t0));
-  }
-  samples.sort((a, b) => a - b);
-  const median = samples[Math.floor(samples.length / 2)];
-  const min = samples[0];
-  console.log(`  ${label.padEnd(22)} median=${fmtMs(median).padStart(7)} ms  min=${fmtMs(min).padStart(7)} ms`);
-  return median;
-}
-
-async function main() {
-  const { values } = parseArgs({
-    options: { "scratch-dir": { type: "string" } },
-  });
-  const scratch = values["scratch-dir"];
-  if (!scratch) { console.error("--scratch-dir required"); process.exit(2); }
-  const blobPath = join(scratch, "pii-weights-full.bin");
-
-  const loader = new ModelLoader({ source: "openai/privacy-filter" });
-  const bundle = await loader.load();
-  const tokenizer = await Tokenizer.fromBundle(bundle);
-
-  console.log("warming up both backends (+ heavy first-call JIT/caching)…");
-  const tjs = new TransformersJsBackend({ bundle, quantization: "int4", device: "auto" });
-  await tjs.warmup();
-  const wasm = new WasmBackend({ weightsUrl: new URL(`file://${blobPath}`), bundle, quantization: "int4", device: "wasm" });
-  await wasm.warmup();
-
-  for (const text of SEEDS) {
-    const enc = tokenizer.encode(text);
-    console.log(`\nT=${enc.tokenIds.length}  input="${text.slice(0, 60)}${text.length > 60 ? "…" : ""}"`);
-    const tjsMs = await measureBackend(tjs, enc.tokenIds, enc.attentionMask, "transformers.js");
-    const wasmMs = await measureBackend(wasm, enc.tokenIds, enc.attentionMask, "wasm (Stage 1)");
-    const speedup = tjsMs / wasmMs;
-    console.log(`  speedup wasm vs tjs:   ${speedup.toFixed(2)}x`);
-  }
-
-  tjs.dispose();
-  wasm.dispose();
-}
-
-await main();

@@ -1,179 +0,0 @@
-#!/usr/bin/env node
-// Micro-benchmark for the Stage 1 kernels. Runs each kernel across a
-// few Phase-D-representative shapes and reports median ns/call + derived
-// GFLOPS for the dense kernels. Pure timing; does not check numerics —
-// use `npm run verify:kernels` for parity.
-//
-//     node scripts/bench-kernels.mjs
-//
-// Shapes chosen to mirror upstream privacy-filter dims:
-//   D (d_model) = 640
-//   Attention head dims: Q=14×64=896, KV=2×64=128
-//   Router = 128 experts
-//   Classifier head = 33 classes
-// No dependencies. Node 20+.
-
-import { readFile } from "node:fs/promises";
-import { fileURLToPath } from "node:url";
-import { dirname, join } from "node:path";
-
-const HERE = dirname(fileURLToPath(import.meta.url));
-const REPO = join(HERE, "..");
-const WASM_PATH = join(REPO, "dist", "pii.wasm");
-
-const WARMUP = 5;
-const ITERS = 50;
-
-async function loadWasm() {
-  const bytes = await readFile(WASM_PATH);
-  const { instance } = await WebAssembly.instantiate(bytes, {});
-  return instance.exports;
-}
-
-function median(xs) {
-  const sorted = [...xs].sort((a, b) => a - b);
-  const mid = sorted.length >>> 1;
-  return sorted.length % 2 === 0
-    ? (sorted[mid - 1] + sorted[mid]) / 2
-    : sorted[mid];
-}
-
-function fmtNs(ns) {
-  if (ns < 1000) return `${ns.toFixed(0)} ns`;
-  if (ns < 1_000_000) return `${(ns / 1000).toFixed(2)} µs`;
-  return `${(ns / 1_000_000).toFixed(3)} ms`;
-}
-
-function time(fn) {
-  const t0 = process.hrtime.bigint();
-  fn();
-  return Number(process.hrtime.bigint() - t0);
-}
-
-async function main() {
-  const ex = await loadWasm();
-
-  const shapes = [
-    { name: "classifier head", T: 8, N: 33, D: 640 },
-    { name: "router         ", T: 8, N: 128, D: 640 },
-    { name: "K/V projection  ", T: 128, N: 128, D: 640 },
-    { name: "Q projection    ", T: 128, N: 896, D: 640 },
-    { name: "O projection    ", T: 128, N: 640, D: 896 },
-  ];
-
-  console.log(`matmul_bf16 — SIMD (${ITERS} iters, ${WARMUP} warmup)`);
-  console.log(`${"shape".padEnd(34)} ${"ns/call".padStart(12)} ${"GFLOPS".padStart(9)}`);
-  for (const s of shapes) {
-    const xBytes = s.T * s.D * 2;
-    const wBytes = s.N * s.D * 2;
-    const bBytes = s.N * 2;
-    const oBytes = s.T * s.N * 2;
-    const xPtr = ex.alloc(xBytes);
-    const wPtr = ex.alloc(wBytes);
-    const bPtr = ex.alloc(bBytes);
-    const oPtr = ex.alloc(oBytes);
-    // Non-zero inputs so the compiler can't elide work. bf16 0x3F80 = 1.0.
-    new Uint16Array(ex.memory.buffer, xPtr, xBytes >>> 1).fill(0x3F80);
-    new Uint16Array(ex.memory.buffer, wPtr, wBytes >>> 1).fill(0x3F00);
-    new Uint16Array(ex.memory.buffer, bPtr, bBytes >>> 1).fill(0);
-
-    for (let i = 0; i < WARMUP; i++) ex.matmul_bf16(xPtr, wPtr, bPtr, oPtr, s.T, s.N, s.D);
-
-    const samples = [];
-    for (let i = 0; i < ITERS; i++) {
-      samples.push(time(() => ex.matmul_bf16(xPtr, wPtr, bPtr, oPtr, s.T, s.N, s.D)));
-    }
-    const med = median(samples);
-    // FLOPs: 2 * T * N * D (mul + add per output element per D step).
-    const flops = 2 * s.T * s.N * s.D;
-    const gflops = flops / med;
-    const label = `T=${s.T} N=${s.N} D=${s.D} (${s.name.trim()})`;
-    console.log(`${label.padEnd(34)} ${fmtNs(med).padStart(12)} ${gflops.toFixed(2).padStart(9)}`);
-    ex.reset();
-  }
-
-  console.log(`\nmatmul_bf16_x_int4block — SIMD (${ITERS} iters, ${WARMUP} warmup)`);
-  console.log(`${"shape".padEnd(34)} ${"ns/call".padStart(12)} ${"GFLOPS".padStart(9)}`);
-  for (const s of shapes) {
-    const xBytes = s.T * s.D * 2;
-    const wBytes = s.N * (s.D / 2) + s.N * (s.D / 32) * 2;
-    const bBytes = s.N * 2;
-    const oBytes = s.T * s.N * 2;
-    const xPtr = ex.alloc(xBytes);
-    const wPtr = ex.alloc(wBytes);
-    const bPtr = ex.alloc(bBytes);
-    const oPtr = ex.alloc(oBytes);
-    new Uint16Array(ex.memory.buffer, xPtr, xBytes >>> 1).fill(0x3F80);
-    new Uint8Array(ex.memory.buffer, wPtr, s.N * (s.D / 2)).fill(0x21); // int4 values 1, 2 alternating
-    new Uint16Array(ex.memory.buffer, wPtr + s.N * (s.D / 2), s.N * (s.D / 32)).fill(0x3C00); // fp16 1.0
-    new Uint16Array(ex.memory.buffer, bPtr, bBytes >>> 1).fill(0);
-
-    const scalesPtr = wPtr + s.N * (s.D / 2);
-    for (let i = 0; i < WARMUP; i++) ex.matmul_bf16_x_int4block(xPtr, wPtr, scalesPtr, 0, bPtr, oPtr, s.T, s.N, s.D);
-    const samples = [];
-    for (let i = 0; i < ITERS; i++) {
-      samples.push(time(() => ex.matmul_bf16_x_int4block(xPtr, wPtr, scalesPtr, 0, bPtr, oPtr, s.T, s.N, s.D)));
-    }
-    const med = median(samples);
-    const flops = 2 * s.T * s.N * s.D;
-    const gflops = flops / med;
-    const label = `T=${s.T} N=${s.N} D=${s.D} (${s.name.trim()})`;
-    console.log(`${label.padEnd(34)} ${fmtNs(med).padStart(12)} ${gflops.toFixed(2).padStart(9)}`);
-    ex.reset();
-  }
-
-  console.log(`\nrms_norm`);
-  console.log(`${"shape".padEnd(34)} ${"ns/call".padStart(12)}`);
-  for (const { T, D, name } of [
-    { T: 8, D: 640, name: "8 tokens" },
-    { T: 128, D: 640, name: "128 tokens" },
-    { T: 1024, D: 640, name: "1024 tokens" },
-  ]) {
-    const xBytes = T * D * 2;
-    const gBytes = D * 2;
-    const oBytes = T * D * 2;
-    const xPtr = ex.alloc(xBytes);
-    const gPtr = ex.alloc(gBytes);
-    const oPtr = ex.alloc(oBytes);
-    new Uint16Array(ex.memory.buffer, xPtr, xBytes >>> 1).fill(0x3F80);
-    new Uint16Array(ex.memory.buffer, gPtr, gBytes >>> 1).fill(0x3F80);
-
-    for (let i = 0; i < WARMUP; i++) ex.rms_norm(xPtr, gPtr, oPtr, T, D, 1e-5);
-    const samples = [];
-    for (let i = 0; i < ITERS; i++) {
-      samples.push(time(() => ex.rms_norm(xPtr, gPtr, oPtr, T, D, 1e-5)));
-    }
-    const label = `T=${T} D=${D} (${name})`;
-    console.log(`${label.padEnd(34)} ${fmtNs(median(samples)).padStart(12)}`);
-    ex.reset();
-  }
-
-  console.log(`\nembed_lookup`);
-  console.log(`${"shape".padEnd(34)} ${"ns/call".padStart(12)}`);
-  for (const { T, V, D, name } of [
-    { T: 8, V: 1024, D: 640, name: "8 tokens" },
-    { T: 128, V: 1024, D: 640, name: "128 tokens" },
-    { T: 1024, V: 1024, D: 640, name: "1024 tokens" },
-  ]) {
-    const iBytes = T * 4;
-    const eBytes = V * D * 2;
-    const oBytes = T * D * 2;
-    const iPtr = ex.alloc(iBytes);
-    const ePtr = ex.alloc(eBytes);
-    const oPtr = ex.alloc(oBytes);
-    const ids = new Int32Array(ex.memory.buffer, iPtr, T);
-    for (let k = 0; k < T; k++) ids[k] = k % V;
-    new Uint16Array(ex.memory.buffer, ePtr, eBytes >>> 1).fill(0x3F80);
-
-    for (let i = 0; i < WARMUP; i++) ex.embed_lookup(ePtr, iPtr, oPtr, T, V, D);
-    const samples = [];
-    for (let i = 0; i < ITERS; i++) {
-      samples.push(time(() => ex.embed_lookup(ePtr, iPtr, oPtr, T, V, D)));
-    }
-    const label = `T=${T} V=${V} D=${D} (${name})`;
-    console.log(`${label.padEnd(34)} ${fmtNs(median(samples)).padStart(12)}`);
-    ex.reset();
-  }
-}
-
-await main();

@@ -1,86 +0,0 @@
-#!/usr/bin/env node
-// End-to-end verification of the WasmBackend. Exercises the full
-// public-shaped path: load .wasm + weight blob, warmup, forward on token
-// IDs, read logits, compare to a PyTorch reference.
-//
-// Against the committed truncated blob (tests/fixtures/pii-weights.bin,
-// 1 layer + 4 experts) this is a fast run. Against a full blob produced
-// by `scripts/convert_weights.py --full --quant-transpose mlp.experts.gate_up_proj --quant-transpose mlp.experts.down_proj`
-// it would exercise all 8 blocks — requires generating the blob + a
-// matching logits fixture separately.
-//
-//     bun scripts/verify-backend-e2e.mjs
-
-import { readFile } from "node:fs/promises";
-import { fileURLToPath } from "node:url";
-import { dirname, join } from "node:path";
-import { WasmBackend } from "../src/js/backends/wasm.ts";
-
-const HERE = dirname(fileURLToPath(import.meta.url));
-const FIXTURES = join(HERE, "..", "tests", "fixtures");
-
-function bf16ToF32(u) {
-  const buf = new ArrayBuffer(4);
-  new DataView(buf).setUint32(0, u << 16, true);
-  return new DataView(buf).getFloat32(0, true);
-}
-
-async function main() {
-  const idsBuf = await readFile(join(FIXTURES, "mdl_input_ids.i32"));
-  const ids = new Int32Array(
-    idsBuf.buffer.slice(idsBuf.byteOffset, idsBuf.byteOffset + idsBuf.byteLength),
-  );
-
-  const expectedBuf = await readFile(join(FIXTURES, "mdl_logits.bf16"));
-  const expectedU16 = new Uint16Array(
-    expectedBuf.buffer.slice(expectedBuf.byteOffset, expectedBuf.byteOffset + expectedBuf.byteLength),
-  );
-
-  const weightsPath = join(FIXTURES, "pii-weights.bin");
-  const weightsUrl = new URL(`file://${weightsPath}`);
-
-  const backend = new WasmBackend({
-    weightsUrl,
-    bundle: undefined,
-    quantization: "int4",
-    device: "wasm",
-  });
-  await backend.warmup();
-
-  const dummyMask = new Uint8Array(ids.length).fill(1);
-  const logits = await backend.forward(ids, dummyMask);
-
-  // Compare f32 outputs to the bf16-upcast expected.
-  if (logits.data.length !== expectedU16.length) {
-    throw new Error(`shape mismatch: got ${logits.data.length}, expected ${expectedU16.length}`);
-  }
-  let maxAbs = 0, maxRel = 0, sumSq = 0, fails = 0;
-  const RELTOL = 0.2, ABSTOL = 1.5;
-  let firstFailIdx = -1;
-  for (let i = 0; i < logits.data.length; i++) {
-    const g = logits.data[i];
-    const w = bf16ToF32(expectedU16[i]);
-    const abs = Math.abs(g - w);
-    const rel = Math.abs(w) > 0 ? abs / Math.abs(w) : abs;
-    if (abs > maxAbs) maxAbs = abs;
-    if (rel > maxRel) maxRel = rel;
-    sumSq += abs * abs;
-    if (abs > Math.max(ABSTOL, RELTOL * Math.abs(w))) {
-      fails++;
-      if (firstFailIdx === -1) firstFailIdx = i;
-    }
-  }
-  const rms = Math.sqrt(sumSq / logits.data.length);
-  const status = fails === 0 ? "PASS" : "FAIL";
-  console.log(
-    `WasmBackend e2e  ${status}  fails=${fails}/${logits.data.length}  ` +
-    `maxAbs=${maxAbs.toExponential(2)}  maxRel=${maxRel.toExponential(2)}  rms=${rms.toExponential(2)}`,
-  );
-  if (fails > 0) {
-    console.log(`    first fail @ ${firstFailIdx}: got ${logits.data[firstFailIdx].toPrecision(6)}, want ${bf16ToF32(expectedU16[firstFailIdx]).toPrecision(6)}`);
-    process.exit(1);
-  }
-  backend.dispose();
-}
-
-await main();

